sys_script_fix.script:
// get all OUs
var grAllOUs = new GlideRecord("x_153465_discovert_discover_office_hierarchy");
grAllOUs.query();

while(grAllOUs.next()){
	if(grAllOUs.u_top_ou == grAllOUs.getUniqueValue()){
		// update the Task Administrator Field for this OU
		new OrganizationalScripts().setTopOUTaskAdministrators(grAllOUs);
	} else {
		// clear the Task Adminstrator field, this is not a top OU
		grAllOUs.u_global_authorities = "";
		grAllOUs.update("Fix Script 2.8.3 - only top OU needs Administrator list");
	}
}
